functional.content:
service_requests = []
medication_requests = []
summary_lines = []

# Ensure optional maps are dictionaries to avoid KeyError
lab_map = lab_code_map if lab_code_map is not None else {}
med_map = medication_code_map if medication_code_map is not None else {}

for code, act in actions.items():
    if act == "repeat_test":
        # Build a minimal ServiceRequest payload
        service_payload = {
            "resourceType": "ServiceRequest",
            "status": "active",
            "intent": "order",
            "code": {
                "coding": [
                    {
                        "code": lab_map.get(code, code)
                    }
                ]
            },
            "subject": {
                "reference": f"Patient/{patient_id}"
            }
        }
        resp = apis.http.post(
            url=f"{base_url}/fhir/ServiceRequest",
            json=service_payload
        )
        service_requests.append(resp)
    elif act == "adjust_medication":
        # Build a minimal MedicationRequest payload
        med_payload = {
            "resourceType": "MedicationRequest",
            "status": "active",
            "intent": "order",
            "medicationCodeableConcept": {
                "coding": [
                    {
                        "code": med_map.get(code, code)
                    }
                ]
            },
            "subject": {
                "reference": f"Patient/{patient_id}"
            }
        }
        resp = apis.http.post(
            url=f"{base_url}/fhir/MedicationRequest",
            json=med_payload
        )
        medication_requests.append(resp)
    else:
        # Any other action is summarized in plain text
        summary_lines.append(f"Observation {code}: recommended action '{act}'.")

summary = "\n".join(summary_lines) if summary_lines else "No additional actions required."

result = {
    "service_requests": service_requests,
    "medication_requests": medication_requests,
    "summary": summary
}

payload = {
    "resourceType": "ServiceRequest",
    "code": {
        "coding": [
            {
                "system": code_system,
                "code": service_code,
                "display": code_display
            }
        ]
    },
    "authoredOn": request_date_iso,
    "status": status,
    "intent": intent,
    "priority": priority,
    "subject": {
        "reference": f"Patient/{patient_id}"
    },
    "occurrenceDateTime": request_date_iso,
    "note": {
        "text": f"Order {code_display} (code {service_code}) for patient {patient_id} on {request_date_iso}."
    }
}

# Post the ServiceRequest to the FHIR server
response = apis.fhir.post(
    f"{base_url}/ServiceRequest",
    json=payload
)

# Optionally, surface only the created resource for downstream steps
created_resource = response.get("resource") if isinstance(response, dict) else response

resource = {
    "resourceType": "ServiceRequest",
    "code": {
        "coding": [
            {
                "system": procedure_cpt_system,
                "code": procedure_cpt_code,
                "display": procedure_cpt_display
            }
        ],
        "text": procedure_cpt_display
    },
    "subject": {
        "reference": f"Patient/{patient_id}"
    },
    "status": status,
    "intent": intent,
    "priority": priority,
    "note": [{"text": note_text}]
}

# Add authoredOn if supplied
if authored_on:
    resource["authoredOn"] = authored_on

response = apis.fhir.post(
    url=f"{base_url}/ServiceRequest",
    json=resource
)

summary_parts = []

# ---- TSH part ----
if tsh_value is None:
    summary_parts.append("TSH not available")
else:
    if isinstance(tsh_value, tuple) and len(tsh_value) == 2:
        val, unit = tsh_value
        summary_parts.append(f"TSH {val}{unit}")
    else:
        summary_parts.append(f"TSH {tsh_value}")

# ---- FT4 part ----
if ft4_value is None:
    summary_parts.append("FT4 not available")
else:
    if isinstance(ft4_value, tuple) and len(ft4_value) == 2:
        val, unit = ft4_value
        summary_parts.append(f"FT4 {val}{unit}")
    else:
        summary_parts.append(f"FT4 {ft4_value}")

# Combine measurements and action into a single sentence
summary = "; ".join(summary_parts) + f". Action: {action}."

# Signal completion to the supervising system
apis.supervisor.complete_task(message=summary)

removal_present = False

for resource_type in ["Procedure", "ServiceRequest"]:
    # Build the initial search URL for the given resource type
    next_url = (
        f"{base_url}/{resource_type}?code={removal_code}&patient={patient_id}&basedOn={insertion_id}&_count={page_size}"
    )
    while next_url and not removal_present:
        # Perform the HTTP GET request
        response = apis.http.get(url=next_url)
        bundle = response.json()

        # If any entry exists, a removal has been documented
        if bundle.get('entry'):
            removal_present = True
            break

        # Look for a pagination link with relation "next"
        next_url = None
        for link in bundle.get('link', []):
            if link.get('relation') == 'next':
                next_url = link.get('url')
                break

    # If we already found a removal, stop checking the other resource type
    if removal_present:
        break

summary_parts = []
for code, obs in lab_results.items():
    if obs:
        qty = obs.get("valueQuantity", {})
        value = qty.get("value")
        unit = qty.get("unit", "")
        summary_parts.append(f"{code}: {value} {unit}".strip())
    else:
        summary_parts.append(f"{code}: not found")

summary = "; ".join(summary_parts)

if any(v is None for v in lab_results.values()):
    action = "Recommend ordering missing labs."
else:
    action = "Proceed with clinical review per protocol."

full_message = f"Patient {patient_id} - {summary}. Action: {action}"
apis.supervisor.complete_task(message=full_message)

order_created = False

# Helper to extract year and month from an ISO‑8601 string (e.g., "2022-03-15T10:20:00+00:00")
def _ym(date_str: str) -> tuple[int, int]:
    date_part = date_str.split('T')[0]  # "2022-03-15"
    year_str, month_str, _ = date_part.split('-')
    return int(year_str), int(month_str)

# Determine whether a booster is needed
need_booster = False
if last_dose_date is None:
    need_booster = True
else:
    # Compute month difference between current_date and last_dose_date
    cur_year, cur_month = _ym(current_date)
    last_year, last_month = _ym(last_dose_date)
    month_diff = (cur_year - last_year) * 12 + (cur_month - last_month)
    if month_diff > max_months:
        need_booster = True

if need_booster:
    payload = {
        "resourceType": "ServiceRequest",
        "code": {
            "coding": [
                {
                    "system": code_system,
                    "code": code,
                    "display": display
                }
            ],
            "text": display
        },
        "authoredOn": authored_on,
        "status": "active",
        "intent": intent,
        "priority": priority,
        "subject": {
            "reference": f"Patient/{patient_id}"
        },
        "occurrenceDateTime": occurrence_datetime
    }
    if note_text:
        payload["note"] = {"text": note_text}

    # POST the ServiceRequest to the FHIR server
    apis.fhir.post_service_request(
        base_url=base_url,
        resource=payload
    )
    order_created = True

# The variable ``order_created`` indicates success/failure to the caller.

# Step 1 – Prepare printable lab values
if tsh_value is None:
    tsh_str = "N/A"
else:
    tsh_str = f"{tsh_value:.1f}"

if free_t4_value is None:
    t4_str = "N/A"
else:
    t4_str = f"{free_t4_value:.1f}"

# Step 2 – Build the concise summary string
summary = f"TSH: {tsh_str} mIU/L, free T4: {t4_str} pmol/L – Action: {action}"

# Step 3 – Send the summary to the supervisor to finish the task
response = apis.supervisor.complete_task(task_id=task_id, result=summary)

# Step 4 – Verify the call succeeded (the tool returns a dict with 'status' and optional 'body')
if isinstance(response, dict) and response.get('status') == 200:
    # Successful completion – keep the whole response for possible downstream use
    pass
else:
    # On failure, set response to None so callers can handle it gracefully
    response = None

procedures = []

# Build initial request URL
url = f"{base_url}/Procedure?code={code}&patient={patient_id}"

# Prepare optional auth header
headers = {}
if auth_token:
    headers["Authorization"] = f"Bearer {auth_token}"

while url:
    response = apis.http.get(url=url, headers=headers)
    if response.status_code != 200:
        raise Exception(f"Failed to fetch procedures, status {response.status_code}")
    bundle = response.json()
    # Extract resources from bundle entries
    for entry in bundle.get("entry", []):
        resource = entry.get("resource")
        if resource:
            procedures.append(resource)
    # Look for a 'next' link to continue paging
    next_url = None
    for link in bundle.get("link", []):
        if link.get("relation") == "next":
            next_url = link.get("url")
            break
    url = next_url

# At this point, `procedures` holds all matching Procedure resources

events = []

# Helper to fetch all pages from a FHIR endpoint
page_url = f"{base_url}/fhir/Procedure?patient={patient_id}&code={','.join(vaccine_codes)}&_count=50"
while page_url:
    bundle = apis.fhir.get(url=page_url)
    for entry in bundle.get('entry', []):
        resource = entry.get('resource', {})
        if resource.get('resourceType') == 'Procedure':
            events.append(resource)
    # Look for the next page link
    next_link = None
    for link in bundle.get('link', []):
        if link.get('relation') == 'next':
            next_link = link.get('url')
            break
    page_url = next_link

# MedicationRequest side (COVID vaccine may be recorded as a medication request)
page_url = f"{base_url}/fhir/MedicationRequest?patient={patient_id}&code={','.join(vaccine_codes)}&_count=50"
while page_url:
    bundle = apis.fhir.get(url=page_url)
    for entry in bundle.get('entry', []):
        resource = entry.get('resource', {})
        if resource.get('resourceType') == 'MedicationRequest':
            events.append(resource)
    next_link = None
    for link in bundle.get('link', []):
        if link.get('relation') == 'next':
            next_link = link.get('url')
            break
    page_url = next_link

# Deduplicate by (resourceType, id)
unique = {}
for ev in events:
    key = (ev.get('resourceType'), ev.get('id'))
    if key not in unique:
        unique[key] = ev

events = list(unique.values())

# Normalise date field for sorting
def get_event_date(ev):
    if ev.get('resourceType') == 'Procedure':
        return ev.get('performedDateTime') or ev.get('occurrenceDateTime')
    if ev.get('resourceType') == 'MedicationRequest':
        return ev.get('authoredOn')
    return None

# Sort descending (most recent first)
events.sort(key=lambda e: get_event_date(e) or '', reverse=True)

records = []

# Helper to perform a GET request with optional auth
def _get(url):
    headers = {}
    if auth_token:
        headers["Authorization"] = f"Bearer {auth_token}"
    response = apis.http.get(url=url, headers=headers)
    # Assume the response object has a .json() method returning the FHIR bundle
    return response.json()

# 1. Retrieve MedicationRequest resources for the patient
med_url = f"{base_url}/MedicationRequest?patient={patient_id}"
while med_url:
    bundle = _get(med_url)
    for entry in bundle.get("entry", []):
        resource = entry.get("resource", {})
        # Keep only COVID‑19 vaccine requests (simple filter on medicationCodeableConcept)
        coding = resource.get("medicationCodeableConcept", {}).get("coding", [])
        if any(c.get("code") == "COVIDVACCINE" for c in coding):
            date = resource.get("authoredOn")
            records.append({
                "resource_type": "MedicationRequest",
                "date": date,
                "details": resource
            })
    # Follow pagination if present
    next_link = None
    for link in bundle.get("link", []):
        if link.get("relation") == "next":
            next_link = link.get("url")
            break
    med_url = next_link

# 2. Retrieve Procedure resources for the patient filtered by COVID‑19 vaccine code
proc_url = f"{base_url}/Procedure?patient={patient_id}&code=COVIDVACCINE"
while proc_url:
    bundle = _get(proc_url)
    for entry in bundle.get("entry", []):
        resource = entry.get("resource", {})
        date = resource.get("performedDateTime") or resource.get("performedPeriod", {}).get("start")
        records.append({
            "resource_type": "Procedure",
            "date": date,
            "details": resource
        })
    next_link = None
    for link in bundle.get("link", []):
        if link.get("relation") == "next":
            next_link = link.get("url")
            break
    proc_url = next_link

# 3. Sort records by date (most recent first)
records.sort(key=lambda r: r["date"] or "", reverse=True)

from datetime import datetime, timezone

# Use supplied authored_on or generate the current UTC timestamp
if authored_on:
    authored_timestamp = authored_on
else:
    authored_timestamp = datetime.now(timezone.utc).replace(microsecond=0).isoformat() + "Z"

payload = {
    "resourceType": "ServiceRequest",
    "code": {
        "coding": [
            {
                "system": "http://www.ama-assn.org/go/cpt",
                "code": cpt_code,
                "display": cpt_display
            }
        ],
        "text": cpt_display
    },
    "authoredOn": authored_timestamp,
    "status": status,
    "intent": intent,
    "priority": priority,
    "subject": {"reference": f"Patient/{patient_id}"},
    "note": {"text": note_text} if note_text else None,
    "occurrenceDateTime": authored_timestamp
}

# Remove the ``note`` field if no note was provided to keep the payload clean
if payload["note"] is None:
    del payload["note"]

# POST the ServiceRequest to the FHIR server
response = apis.fhir.create_service_request(
    base_url=base_url,
    resource=payload
)

results = []

# Initialise the first request URL
url = f"{base_url}/MedicationRequest?patient=Patient/{patient_id}&_count={page_limit}"

headers = {}
if auth_token:
    headers["Authorization"] = f"Bearer {auth_token}"

while url:
    response = apis.fhir.get(url=url, headers=headers)
    # Expect a FHIR Bundle JSON object
    bundle = response.json()
    entries = bundle.get("entry", [])
    for entry in entries:
        resource = entry.get("resource", {})
        if medication_text:
            med_desc = resource.get("medicationCodeableConcept", {}).get("text", "")
            if medication_text.lower() in med_desc.lower():
                results.append(resource)
        else:
            results.append(resource)
    # Determine next page URL from bundle.link where relation == "next"
    next_url = None
    for link in bundle.get("link", []):
        if link.get("relation") == "next":
            next_url = link.get("url")
            break
    url = next_url

# ``results`` now holds all matching MedicationRequest resources.

filtered_requests = []
for req in med_requests:
    # Check that the request is active
    if req.get("status") != "active":
        continue
    # Navigate to the medication code (supports both direct coding and reference lookup placeholders)
    med_concept = req.get("medicationCodeableConcept", {})
    codings = med_concept.get("coding", [])
    if not isinstance(codings, list):
        continue
    # Determine if any coding matches an opioid code
    is_opioid = False
    for coding in codings:
        code = coding.get("code")
        if isinstance(code, str) and code in opioid_codes:
            is_opioid = True
            break
    if is_opioid:
        filtered_requests.append(req)
# Result stored in filtered_requests

summary_messages = []

# 1. Summarize the procedure lookup result
if procedure_found:
    # most_recent_date is guaranteed to be a string when found
    summary_messages.append(
        f"Most recent CT Abdomen procedure was performed on {most_recent_date}."
    )
else:
    summary_messages.append(
        "No prior CT Abdomen procedure (IMGCT0491 or IMGIL0001) found for the patient."
    )

# 2. Summarize the order outcome (if an order attempt was made)
if order_placed:
    # Extract useful fields safely
    code = order_details.get("code", "unknown CPT") if order_details else "unknown CPT"
    indication = order_details.get("indication", "unspecified indication") if order_details else "unspecified indication"
    summary_messages.append(
        f"A new CT Abdomen with IV contrast (CPT {code}) has been ordered for {indication}."
    )
else:
    # No order placed – could be because the existing study is recent enough
    if not procedure_found:
        # No prior study and order failed – include a generic note
        summary_messages.append(
            "Attempted to place a new order, but the operation did not succeed."
        )
    else:
        # Existing study is recent; no new order needed
        summary_messages.append(
            "Existing study is within the acceptable time window; no new order was placed."
        )

observations = []
page = 0
while True:
    # Call the FHIR Observation search API for the given code and patient
    bundle = apis.fhir.search_observations(
        base_url=base_url,
        code=code,
        patient_id=patient_id,
        page=page,
        page_limit=page_limit
    )
    # Expect the bundle to contain an "entry" list; if missing or empty, stop paging
    entries = bundle.get("entry", [])
    if not entries:
        break
    # Extract the Observation resources from the bundle entries
    for entry in entries:
        resource = entry.get("resource", {})
        if resource.get("resourceType") == "Observation":
            observations.append(resource)
    page += 1

# Determine the most recent observation based on effectiveDateTime
latest_observation = {}
if observations:
    # Sort observations by effectiveDateTime descending; missing dates are treated as the earliest
    observations.sort(
        key=lambda obs: obs.get("effectiveDateTime", ""),
        reverse=True
    )
    most_recent = observations[0]
    # Extract the value; handle both quantity and string representations
    value = None
    if "valueQuantity" in most_recent:
        value = most_recent["valueQuantity"].get("value")
    elif "valueString" in most_recent:
        value = most_recent["valueString"]
    elif "valueCodeableConcept" in most_recent:
        value = most_recent["valueCodeableConcept"].get("text")
    latest_observation = {
        "value": value,
        "date": most_recent.get("effectiveDateTime"),
        "raw": most_recent
    }
else:
    latest_observation = {}

records = []

# Build the initial request URL and parameters
url = f"/fhir/{resource_type}"
params = {
    "patient": patient_id,
    "code": ",".join(vaccine_codes),
    "_count": 50  # reasonable page size; adjust if needed
}

while True:
    bundle = apis.fhir.search(url=url, params=params)
    if not bundle or "entry" not in bundle:
        break
    # Extract resources from the current bundle page
    for entry in bundle["entry"]:
        if "resource" in entry:
            records.append(entry["resource"])
    # Look for a 'next' link to continue paging
    next_link = None
    for link in bundle.get("link", []):
        if link.get("relation") == "next":
            next_link = link.get("url")
            break
    if not next_link:
        break
    # Prepare for the next iteration using the absolute URL provided by the server
    # The API wrapper expects the path portion only; strip domain if present
    if next_link.startswith("http"):
        # split on the first '/' after the scheme and host
        next_path = "/".join(next_link.split("/")[3:])
    else:
        next_path = next_link
    url = f"/{next_path}" if not next_path.startswith("/") else next_path
    # Reset params because pagination URL already contains all needed query values
    params = {}

# The variable ``records`` now holds all matching vaccination resources.

summary = ""
if service_request is None:
    summary = f"No booster needed for patient {patient_id}."
else:
    summary = f"Booster ordered for patient {patient_id}."

# Append any optional custom note
if custom_note:
    summary = f"{summary} {custom_note}"

# Signal task completion to the supervisor
apis.supervisor.complete_task([summary])

observations = []
url = f"{base_url}/fhir/Observation?code={code}&patient={patient_id}"
request_headers = headers if headers is not None else {}
while url:
    response = apis.http.get(url=url, headers=request_headers)
    bundle = response.json()
    entries = bundle.get("entry", [])
    for entry in entries:
        observations.append(entry.get("resource", {}))
    # locate the next page URL, if any
    next_url = None
    for link in bundle.get("link", []):
        if link.get("relation") == "next":
            next_url = link.get("url")
            break
    url = next_url

summary = ''
if detail_message:
    summary = detail_message.strip()
else:
    if action_taken:
        summary = 'Action performed and task completed.'
    else:
        summary = 'No action required; task completed.'

# Call the supervisor to mark the task as finished with the generated summary
response = apis.supervisor.complete_task(
    task_id=task_id,
    result=summary
)

# Normalize the response – if the tool does not return a JSON‑like object, fall back to empty dict
if hasattr(response, 'json'):
    completed = response.json()
else:
    completed = {}

# ``completed`` now holds the supervisor's acknowledgement (or empty dict on failure)

payload = {
    "resourceType": "ServiceRequest",
    "code": {
        "coding": [
            {
                "system": code_system,
                "code": code_cpt,
                "display": code_display
            }
        ]
    },
    "authoredOn": authored_on if authored_on else "2023-01-01T00:00:00Z",  # caller may override
    "status": status,
    "intent": intent,
    "priority": priority,
    "subject": {
        "reference": f"Patient/{patient_id}"
    },
    "note": {
        "text": indication
    }
}

# POST the ServiceRequest to the FHIR server
response = apis.fhir.create_service_request(
    base_url=base_url,
    resource=payload
)

med_requests = []

page = 0
page_size = 50  # reasonable page size to balance request load and round‑trips
while True:
    # Build query parameters for the MedicationRequest endpoint
    query = {
        "patient": patient_id,
        "_page": str(page),
        "_count": str(page_size)
    }
    if medication_code:
        query["medication.code"] = medication_code
    if start_date:
        query["date"] = f"ge{start_date}"  # FHIR date filter: greater or equal

    # Perform the GET request against the MedicationRequest endpoint
    response = apis.fhir.search(
        base_url=base_url,
        resource_type="MedicationRequest",
        params=query
    )

    # Expect a FHIR Bundle; extract entries if present
    bundle = response.get("entry", [])
    if not bundle:
        break  # No more entries, exit pagination loop

    for entry in bundle:
        resource = entry.get("resource", {})
        if resource.get("resourceType") == "MedicationRequest":
            med_requests.append(resource)

    page += 1

# Helper to extract the authoredOn date for sorting
def _extract_date(mr: dict) -> str:
    return mr.get("authoredOn", "")

# Sort medication requests by authoredOn (most recent first)
med_requests.sort(key=_extract_date, reverse=True)

# The variable `med_requests` now holds the ordered list of matching MedicationRequest resources.

import json

# Determine authoredOn date
if today_str:
    authored_on = today_str.split('T')[0]
else:
    dt_mod = __import__('datetime')
    authored_on = dt_mod.date.today().isoformat()

# Build MedicationRequest payload
med_req = {
    "resourceType": "MedicationRequest",
    "status": "active",
    "intent": "order",
    "medicationCodeableConcept": {
        "coding": [
            {
                "system": "http://www.ama-assn.org/go/cpt",
                "code": vaccine_code,
                "display": vaccine_display
            }
        ],
        "text": vaccine_display
    },
    "subject": {
        "reference": f"Patient/{patient_id}"
    },
    "authoredOn": authored_on,
    "dosageInstruction": [
        {
            "route": {"text": route_text},
            "doseAndRate": [
                {
                    "doseQuantity": {
                        "value": dosage_value,
                        "unit": dosage_unit
                    }
                }
            ]
        }
    ]
}

# Convert to JSON string for POST body (some FHIR servers accept dict directly)
payload_str = json.dumps(med_req)

# POST to FHIR server
url = f"{base_url}/MedicationRequest"
response = apis.fhir.post(url=url, body=payload_str)

# The variable ``response`` holds the server's reply and will be the final output of the skill.

url = f"{base_url}/Observation?code={code}&patient={patient_id}&_sort=-date&_count=1"

headers = {}
if auth_token:
    headers["Authorization"] = f"Bearer {auth_token}"

response = apis.http.get(url=url, headers=headers)

# Expecting a FHIR Bundle; if no entries, return None
entries = response.get("entry", [])
if entries:
    observation = entries[0].get("resource")
else:
    observation = None

query_url = f"{base_url}/fhir/Procedure?code={procedure_code}&patient={patient_id}&date=ge{cutoff_iso}"

response = apis.http.get(
