def _med_is_opioid(coding_list, text_field=None):
    """Return True if any coding display or the free‑text contains an opioid identifier."""
    if not coding_list:
        return False
    for coding in coding_list:
        display = coding.get("display", "").lower()
        if any(opioid in display for opioid in opioid_terms):
            return True
    if text_field:
        txt = text_field.lower()
