# Helper to convert ISO‑8601 date to total months since year 0
def iso_to_months(date_str: str) -> int:
    parts = date_str.split('-')
    year = int(parts[0])
    month = int(parts[1]) if len(parts) > 1 else 1
    return year * 12 + month

