# Helper to resolve a dotted path inside a dict safely
def resolve_path(data: dict, path: str):
    parts = path.split('.')
    cur = data
    for p in parts:
        if isinstance(cur, dict) and p in cur:
            cur = cur[p]
        else:
            return None
    return cur

for code, obs in lab_results.items():
