    # Retrieve threshold bounds
    bounds = thresholds.get(code)
    if not bounds:
        continue
    low, high = bounds

    # Build recommendation based on comparison
    if low is not None and value < low:
        recommendations.append(f"{code} low ({value} < {low}) – consider increase medication")
    elif high is not None and value > high:
        recommendations.append(f"{code} high ({value} > {high}) – consider decrease medication")
    else:
        recommendations.append(f"{code} within range ({value}) – no action")

