def _parse_iso_date(date_str: str):
    # Simple ISO‑8601 date parser without external imports
    # Handles full datetime strings like "2023-04-15T00:00:00+00:00" or plain dates "2023-04-15"
    if not date_str:
        return None
    # Split at 'T' to discard time and timezone information
    date_part = date_str.split('T')[0]
    year, month, day = map(int, date_part.split('-'))
    return datetime.date(year, month, day)

